export class ProgramLanguajeSeeder implements Seeder {
  readonly name = 'ProgramLanguajeSeeder';

  async run(dataSource: DataSource): Promise<void> {
    const repo = dataSource.getRepository(ProgramLanguajeEntity);

    const count = await repo.count();
    if (count > 0) {
      console.log(`  ⏭  ${this.name}: tabla ya tiene datos, saltando.`);
      return;
    }

    const entities: Partial<ProgramLanguajeEntity>[] = languages.map((lang) => ({
      id: uuidv4(),
      name: lang.name,
      description: lang.description,
      difficulty: lang.difficulty,
    }));

    // Insert in batches of 200 to avoid query size limits
    const batchSize = 200;
    let inserted = 0;
    for (let i = 0; i < entities.length; i += batchSize) {
      const batch = entities.slice(i, i + batchSize);
      await repo.save(batch);
      inserted += batch.length;
    }

    console.log(`  ✅ ${this.name}: ${inserted} lenguajes insertados.`);
  }
}
